void sem_post(sem_t *s) {
 pthread_mutex_lock(&s->m);
 s->count++;
 pthread_cond_signal(&s->cv);
 /* A woken thread must acquire the lock, so it will also have to wait until we call unlock*/

 pthread_mutex_unlock(&s->m);
}
