void sem_wait(sem_t *s) {
 pthread_mutex_lock(&s->m);
 while (s->count == 0) {
 pthread_cond_wait(&s->cv, &s->m); /*unlock mutex, wait, relock mutex*/
 }
 s->count--;
 pthread_mutex_unlock(&s->m);
}
